import { Mastra, Agent, Tool, VectorStore } from 'mastra';
import { z } from 'zod';

const mastra = new Mastra();

const orderLookupTool = new Tool({
  name: 'order_lookup',
  description: 'Lookup customer order by ID',
  schema: z.object({
    orderId: z.string().describe('Order ID'),
  }),
  execute: async ({ orderId }) => {
    // Salesforce CRM integration
    const order = await fetchSalesforceOrder(orderId);
    return { status: order.status, total: order.total };
  },
});

const supportAgent = new Agent({
  name: 'support-agent',
  tools: [orderLookupTool],
  vectorStore: new VectorStore({ /* KB config */ }),
  systemPrompt: 'You are a helpful customer support agent...',
});

mastra.registerAgent(supportAgent);

import { Workflow, Step } from 'mastra';

const ticketWorkflow = new Workflow({
  name: 'create-support-ticket',
  steps: [
    new Step({
      name: 'validate_issue',
      llmPrompt: 'Classify issue severity and extract PII...',
      outputSchema: z.object({
        severity: z.enum(['low', 'medium', 'high']),
        piiFiltered: z.boolean(),
        ticketData: z.object({}),
      }),
    }),
    new Step({
      name: 'create_ticket',
      tools: [ticketCreationTool],
      condition: (prev) => prev.severity !== 'low',
    }),
  ],
});

const retrievalStep = new Step({
  name: 'retrieve_context',
  execute: async (input) => {
    const memory = await agentMemory.getRecentMessages(input.sessionId);
    const kbResults = await vectorStore.similaritySearch(input.query);
    const crmData = await crmClient.getCustomerProfile(input.customerId);

    return {
      combinedContext: [...memory, ...kbResults, crmData],
      sources: ['memory', 'kb', 'crm'],
    };
  },
});

const finalResponseStep = new Step({
  name: 'generate_response',
  llmPrompt: `Generate helpful response. ESCALATE if: refund>1000, legal/compliance, VIP customer...`,
  outputSchema: z.object({
    response: z.string(),
    requiresEscalation: z.boolean().default(false),
    escalationReason: z.string().optional(),
  }),
  postProcess: (output) => {
    if (output.requiresEscalation) {
      triggerHumanEscalation(output.escalationReason);
    }
    return output;
  },
});

