import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  projectId: 'cs-mastra-prod',
});

const validatedRetrieval = new Step({
  name: 'vex_retrieval_validation',
  execute: async (input) => {
    const context = await retrievalStep.execute(input);

    const verified = await vex.verify({
      data: context.combinedContext,
      checks: [
        'temporal_freshness',
        {
          type: 'json_schema',
          schema: {
            type: 'array',
            items: { type: 'object', properties: { timestamp: { type: 'string' } } },
          },
        },
      ],
      riskProfile: 'high',
    });

    if (!verified.passed) throw new Error('Context validation failed');
    return context;
  },
});

const safeOrderLookup = orderLookupTool.overrideExecute(async (params) => {
  const rawResult = await originalExecute(params);

  const verified = await vex.verify({
    data: rawResult,
    checks: [
      {
        type: 'json_schema',
        schema: z.object({
          status: z.string(),
          total: z.number(),
          orderId: z.string(),
        }).parse,
      },
      'pii_filtering',
      { type: 'regex', pattern: 'PII_BLOCKED' },
    ],
  });

  return verified.cleanData;
});

const guardedResponseStep = finalResponseStep.overridePostProcess(async (output) => {
  const verified = await vex.verify({
    data: output,
    checks: [
      'response_accuracy',
      'tone_consistency',
      {
        type: 'policy_compliance',
        policies: ['no_refunds_without_approval', 'vip_escalation'],
      },
      'pii_filtering',
      {
        type: 'custom',
        name: 'escalation_triggers',
        fn: (data) => data.requiresEscalation || data.severity === 'high',
      },
    ],
    riskProfile: 'high',
  });

  return {
    ...output,
    verified: verified.passed,
    issues: verified.issues,
  };
});
